const fs = require('fs');
const path = require('path');
const Joi = require('joi');
const logger = require('../../../common/logger');

let cachedProblems;

const MAX_LIMIT = 50;

/**
 * Normalize tags filter into a lowercase array.
 * @param {string|Array<string>} rawTags
 * @returns {Array<string>}
 */
function normalizeTags(rawTags) {
  if (!rawTags && rawTags !== '') {
    return [];
  }
  const list = Array.isArray(rawTags) ? rawTags : String(rawTags).split(',');
  return list
    .map((tag) => String(tag || '').trim().toLowerCase())
    .filter((tag) => tag);
}

/**
 * Check whether the problem contains at least one of the requested tags.
 * @param {Object} problem
 * @param {Array<string>} tags
 * @returns {boolean}
 */
function problemHasTags(problem, tags) {
  if (!tags || tags.length === 0) {
    return true;
  }
  if (!problem.tags || !Array.isArray(problem.tags)) {
    return false;
  }
  const problemTags = problem.tags.map((t) => t.toLowerCase());
  return tags.some((tag) => problemTags.includes(tag));
}

/**
 * Load problems from JSON file and cache them.
 * @returns {Array<Object>} problems
 */
function loadProblems() {
  if (cachedProblems) {
    return cachedProblems;
  }
  const filePath = path.join(__dirname, '..', '..', '..', 'data', 'problems.json');
  const raw = fs.readFileSync(filePath, 'utf8');
  cachedProblems = JSON.parse(raw);
  return cachedProblems;
}

/**
 * Aggregate component statistics for a problem.
 * @param {Object} problem
 * @returns {Object} componentStats
 */
function aggregateComponentStats(problem) {
  const languages = {};
  const statusCounts = {};
  let maxPoints = 0;

  if (Array.isArray(problem.components)) {
    problem.components.forEach((component) => {
      // Count languages
      if (component.language) {
        languages[component.language] = (languages[component.language] || 0) + 1;
      }
      // Count status
      if (component.status) {
        statusCounts[component.status] = (statusCounts[component.status] || 0) + 1;
      }
      // Track max points
      if (typeof component.points === 'number' && component.points > maxPoints) {
        maxPoints = component.points;
      }
    });
  }

  return {
    languages,
    statusCounts,
    maxPoints
  };
}

